__kernel void dynproc_kernel(
    const int iteration,
    __global int* gpuWall,
    __global int* gpuSrc,
    __global int* gpuResults,
    const int cols,
    const int rows,
    const int startStep,
    const int border,
    const int HALO,
    __local int* prev,
    __local int* result,
    __global int* outputBuffer)
{
    (void)rows;
    (void)border;
    (void)HALO;
    (void)prev;
    (void)result;
    (void)outputBuffer;

    if (get_group_id(0) != 0 || get_local_id(0) != 0) {
        return;
    }

    __global int* src = gpuSrc;
    __global int* dst = gpuResults;

    for (int i = 0; i < iteration; i++) {
        int wall_row_offset = (startStep + i) * cols;

        for (int n = 0; n < cols; n++) {
            int m = src[n];
            if (n > 0) {
                int v = src[n - 1];
                if (v < m) m = v;
            }
            if (n < cols - 1) {
                int v = src[n + 1];
                if (v < m) m = v;
            }
            dst[n] = gpuWall[wall_row_offset + n] + m;
        }

        __global int* temp = src;
        src = dst;
        dst = temp;
    }

    if (iteration > 0 && src != gpuResults) {
        for (int n = 0; n < cols; n++) {
            gpuResults[n] = src[n];
        }
    }
}
